```bash
cat <<'EOF' > /tmp/fix.cpp
void SCEVExpanderCleaner::cleanup() {
  // Result is used, nothing to remove.
  if (ResultUsed)
    return;

  // Restore original poison flags.
  for (auto [I, Flags] : Expander.OrigFlags)
    Flags.apply(I);

  auto InsertedInstructions = Expander.getAllInsertedInstructions();
#ifndef NDEBUG
  SmallPtrSet<Instruction *, 8> InsertedSet(InsertedInstructions.begin(),
                                            InsertedInstructions.end());
  (void)InsertedSet;
#endif
  // Remove sets with value handles.
  Expander.clear();

  // Remove all inserted instructions.
  for (Instruction *I : reverse(InsertedInstructions)) {
#ifndef NDEBUG
    bool AllUsersInInsertedSet = all_of(I->users(),
                  [&InsertedSet](Value *U) {
                    return InsertedSet.contains(cast<Instruction>(U));
                  });
    if (!AllUsersInInsertedSet) {
      // Allow users that are phi nodes in different loops (issue #121518)
      bool AllUsersArePhiNodes = all_of(I->users(), [](Value *U) {
        return isa<PHINode>(U);
      });
      assert((AllUsersInInsertedSet || AllUsersArePhiNodes) && 
             "removed instruction should only be used by instructions inserted "
             "during expansion or phi nodes");
    }
#endif
    assert(!I->getType()->isVoidTy() &&
           "inserted instruction should have non-void types");
    I->replaceAllUsesWith(PoisonValue::get(I->getType()));
    I->eraseFromParent();
  }
}
EOF
